package com.securebank.app;

import android.app.Application;
import android.content.Context;
import android.os.StrictMode;
import android.util.Log;

import com.securebank.app.security.SecurityManager;
import com.securebank.app.security.RootDetector;

public class BankingApplication extends Application {

    private static final String TAG = "BankingApp";
    private SecurityManager securityManager;

    @Override
    public void onCreate() {
        super.onCreate();

        if (BuildConfig.DEBUG) {
            StrictMode.setThreadPolicy(new StrictMode.ThreadPolicy.Builder()
                    .detectAll()
                    .penaltyLog()
                    .build());
        }

        securityManager = new SecurityManager(this);

        if (RootDetector.isDeviceRooted()) {
            Log.w(TAG, "Rooted device detected - restricting functionality");
        }
    }

    public SecurityManager getSecurityManager() {
        return securityManager;
    }
}

